function standardElephantCount(){return state.towers.filter(t=>t.towerType!=='foodie').length}
function reservedElephantCount(){return standardElephantCount()+((isWaterElephantPlacement()||['eyewear','gas','splash'].includes(state.placement))?1:0)}
function reservedFoodieCount(){return state.towers.filter(t=>t.towerType==='foodie').length+(state.placement==='foodie'?1:0)}
function reservedTotalUnitCount(){return state.towers.length+state.papayas.length+state.goldenPapayas.length+(state.placement?1:0)}
function canReserveElephant(){return reservedElephantCount()<CONFIG.ELEPHANT_LIMIT&&reservedTotalUnitCount()<CONFIG.TOTAL_UNIT_LIMIT}
function canReserveFoodie(){return reservedFoodieCount()<CONFIG.FOODIE_ELEPHANT_LIMIT&&reservedTotalUnitCount()<CONFIG.TOTAL_UNIT_LIMIT}
function canPlaceReservedElephant(type){return(type==='foodie'?state.towers.filter(t=>t.towerType==='foodie').length<CONFIG.FOODIE_ELEPHANT_LIMIT:standardElephantCount()<CONFIG.ELEPHANT_LIMIT)&&state.towers.length+state.papayas.length+state.goldenPapayas.length<CONFIG.TOTAL_UNIT_LIMIT}
