function dist(a,b){return Math.hypot(a.x-b.x,a.y-b.y)}
function pointSegmentDistance(p,a,b){const dx=b.x-a.x,dy=b.y-a.y;const t=Math.max(0,Math.min(1,((p.x-a.x)*dx+(p.y-a.y)*dy)/(dx*dx+dy*dy)));return Math.hypot(p.x-(a.x+t*dx),p.y-(a.y+t*dy))}
function validPlacement(p){if(p.x<TOWER_R+10||p.x>CONFIG.WORLD_WIDTH-TOWER_R-10||p.y<TOWER_R+10||p.y>CONFIG.WORLD_HEIGHT-TOWER_R-10)return false;for(let i=0;i<path.length-1;i++)if(pointSegmentDistance(p,path[i],path[i+1])<TRACK_WIDTH/2+TOWER_R+5)return false;return !state.towers.concat(state.papayas,state.goldenPapayas).some(unit=>dist(unit,p)<TOWER_R*2+10)}
function totalTrackLength(){let total=0;for(let i=0;i<path.length-1;i++)total+=dist(path[i],path[i+1]);return total}
function earlyTrackSegments(){const limit=totalTrackLength()*CONFIG.TUTORIAL_EARLY_TRACK_FRACTION,segments=[];let progress=0;for(let i=0;i<path.length-1&&progress<limit;i++){const a=path[i],end=path[i+1],length=dist(a,end),available=Math.min(length,limit-progress),ratio=length?available/length:0,b=ratio>=1?end:{x:a.x+(end.x-a.x)*ratio,y:a.y+(end.y-a.y)*ratio};segments.push({a,b,startProgress:progress,length:available,index:i});progress+=available}return segments}
function segmentLengthInsideCircle(center,a,b,radius){const dx=b.x-a.x,dy=b.y-a.y,length=Math.hypot(dx,dy);if(!length)return 0;const fx=a.x-center.x,fy=a.y-center.y,A=dx*dx+dy*dy,B=2*(fx*dx+fy*dy),C=fx*fx+fy*fy-radius*radius,discriminant=B*B-4*A*C;if(discriminant<0)return C<=0?length:0;const root=Math.sqrt(discriminant),start=Math.max(0,(-B-root)/(2*A)),end=Math.min(1,(-B+root)/(2*A));return Math.max(0,end-start)*length}
function tutorialTrackCoverage(p,radius=CONFIG.ELEPHANT_RADIUS){return earlyTrackSegments().reduce((sum,segment)=>sum+segmentLengthInsideCircle(p,segment.a,segment.b,radius),0)}
function tutorialPlacementGuidanceActive(){return !!(state?.tutorialActive&&state.placement==='elephant'&&tutorialData.step>=6&&tutorialData.step<=8)}
function usefulTutorialPlacement(p){return validPlacement(p)&&tutorialTrackCoverage(p)>=CONFIG.TUTORIAL_MINIMUM_TRACK_COVERAGE}
function placementAllowed(p){return validPlacement(p)&&(!tutorialPlacementGuidanceActive()||usefulTutorialPlacement(p))}
function tutorialVisibleBounds(){return{left:TOWER_R+10,right:CONFIG.WORLD_WIDTH-TOWER_R-10,top:state.cameraY+TOWER_R+10,bottom:Math.min(CONFIG.WORLD_HEIGHT,state.cameraY+viewportWorldHeight())-TOWER_R-10}}
function tutorialPlacementCandidates(minimumCoverage=CONFIG.TUTORIAL_MINIMUM_TRACK_COVERAGE){const bounds=tutorialVisibleBounds(),minimumOffset=TRACK_WIDTH/2+TOWER_R+5+CONFIG.TUTORIAL_RECOMMENDATION_CLEARANCE,offsets=[minimumOffset,minimumOffset+(CONFIG.ELEPHANT_RADIUS-minimumOffset)*.45,CONFIG.ELEPHANT_RADIUS-12],seen=new Set(),candidates=[];for(const segment of earlyTrackSegments()){const dx=segment.b.x-segment.a.x,dy=segment.b.y-segment.a.y,length=Math.hypot(dx,dy);if(!length)continue;const nx=-dy/length,ny=dx/length,steps=Math.max(1,Math.ceil(length/CONFIG.TUTORIAL_RECOMMENDATION_SAMPLE_STEP));for(let step=0;step<=steps;step++){const ratio=step/steps,q={x:segment.a.x+dx*ratio,y:segment.a.y+dy*ratio},progress=segment.startProgress+length*ratio;for(const side of [-1,1])for(const offset of offsets){const p={x:Math.round(q.x+nx*offset),y:Math.round(q.y+ny*offset)};if(p.x<bounds.left||p.x>bounds.right||p.y<bounds.top||p.y>bounds.bottom)continue;const key=`${p.x},${p.y}`;if(seen.has(key)||!validPlacement(p))continue;seen.add(key);const coverage=tutorialTrackCoverage(p);if(coverage<minimumCoverage)continue;const bendDistance=Math.min(...path.slice(1,-1).map(bend=>dist(p,bend))),unitClearance=Math.min(180,...state.towers.concat(state.papayas,state.goldenPapayas).map(unit=>dist(p,unit))),viewportMargin=Math.min(p.x-bounds.left,bounds.right-p.x,p.y-bounds.top,bounds.bottom-p.y),score=coverage*4-progress*.025+Math.max(0,130-bendDistance)*.8+Math.min(120,unitClearance)*.08+Math.min(100,viewportMargin)*.04;candidates.push({...p,coverage,progress,score})}}}return candidates.sort((a,b)=>b.score-a.score||a.progress-b.progress)}
const tutorialPlacementGuidanceBeforeStarterGift=tutorialPlacementGuidanceActive,tutorialPlacementCandidatesBeforeStarterGift=tutorialPlacementCandidates;
tutorialPlacementGuidanceActive=function(){return tutorialPlacementGuidanceBeforeStarterGift()||!!(state?.tutorialActive&&tutorialData.step===9&&state.starterGift?.giftPlacementPending)}
tutorialPlacementCandidates=function(minimumCoverage=CONFIG.TUTORIAL_MINIMUM_TRACK_COVERAGE){const candidates=tutorialPlacementCandidatesBeforeStarterGift(minimumCoverage);if(!(isStarterGiftPlacement()||state.starterGift?.giftPlacementPending&&tutorialData.step===9))return candidates;const firstWater=state.towers.find(t=>t.towerType==='base'&&!t.starterGift);return firstWater?candidates.filter(candidate=>dist(candidate,firstWater)>=CONFIG.TUTORIAL_SECOND_PLACEMENT_SEPARATION):candidates}
function tutorialGuideSignature(){const units=state.towers.concat(state.papayas,state.goldenPapayas).map(unit=>`${Math.round(unit.x)},${Math.round(unit.y)}`).join(';');return`${tutorialData.step}|${state.placement}|${state.cameraY.toFixed(1)}|${CONFIG.WORLD_WIDTH}x${viewportWorldHeight().toFixed(1)}|${units}`}
function updateTutorialPlacementGuide(){if(!tutorialPlacementGuidanceActive()){tutorialPlacementGuide={signature:'',recommended:null,fallback:[]};return tutorialPlacementGuide}const signature=tutorialGuideSignature();if(tutorialPlacementGuide.signature===signature)return tutorialPlacementGuide;const candidates=tutorialPlacementCandidates(),fallback=candidates.length?candidates.slice(0,12):tutorialPlacementCandidates(1).slice(0,12);tutorialPlacementGuide={signature,recommended:candidates[0]||null,fallback};return tutorialPlacementGuide}
function buy(){if(state.status!=='playing'||!canReserveElephant())return;const gift=starterGiftState();if(gift.paidPlacementPending){state.placement='elephant';updateUI();return}if(gift.giftPlacementPending){state.placement='starterGiftElephant';showEncyclopediaNotice('Starter Gift: Place your second Water Elephant!');updateUI();return}if(isStarterWaveOne()&&!gift.firstPaidPurchased&&state.currency>=CONFIG.waterElephantCost){state.currency-=CONFIG.waterElephantCost;gift.firstPaidPurchased=true;gift.paidPlacementPending=true;state.placement='elephant';tutorialAction('bought');updateUI();return}if(state.currency>=CONFIG.waterElephantCost){state.placement='elephant';tutorialAction('bought');updateUI()}}
function buyEyewear(){if(state.status==='playing'&&state.currency>=CONFIG.eyewearElephantCost&&canReserveElephant()){state.placement='eyewear';updateUI()}}
function buyFoodie(){if(state.status==='playing'&&state.currency>=CONFIG.foodieElephantCost&&canReserveFoodie()){state.placement='foodie';updateUI()}}
function buyGasMask(){if(state.status==='playing'&&state.currency>=CONFIG.gasMaskElephantCost&&canReserveElephant()){state.placement='gas';showContextTutorial('gas','Gas Mask Elephants are immune to Fume Orbs.','#buyGasMask');updateUI()}}
function buySplash(){if(state.status==='playing'&&state.currency>=CONFIG.splashElephantCost&&canReserveElephant()){state.placement='splash';showContextTutorial('splash','Splash Elephants use a full-range water pulse every 5 seconds, hitting every non-ghost orb in range for low damage.','#buySplash');updateUI()}}
function buyPapaya(){if(state.status==='playing'&&state.currency>=CONFIG.papayaPlantCost&&reservedPapayaCount()<CONFIG.PAPAYA_LIMIT&&reservedTotalUnitCount()<CONFIG.TOTAL_UNIT_LIMIT){state.placement='papaya';updateUI()}}
function buyGoldenPapaya(){if(state.status==='playing'&&state.currency>=CONFIG.goldenPapayaPlantCost&&reservedGoldenPapayaCount()<CONFIG.maximumGoldenPapayaPlants&&reservedTotalUnitCount()<CONFIG.TOTAL_UNIT_LIMIT){state.placement='goldenPapaya';updateUI()}}
