function launchWave(){if(state.tutorialActive&&tutorialData.step<9)return;if(!canStartWave())return;state.autoCountdown=null;const wave=nextWaveNumber(),spawnSequence=buildWaveSequence(wave),total=spawnSequence.length;if(state.wave===0)state.startingWave=wave;state.wave=wave;state.waveJobs.push({wave,total,normalTotal:ballsForWave(wave),spawnSequence,spawned:0,resolved:0,destroyed:0,spawnTimer:.12,spawnInterval:spawnIntervalForWave(wave),rewarded:false,completionRewardIssued:false,completionRewardAmount:null});burst(28,115,'#ffb12e',16,75);tutorialAction('wave');updateUI()}
ui.startWave.addEventListener('click',launchWave);
ui.autoWaves.addEventListener('change',()=>{if(state.tutorialActive&&tutorialData.step<19){ui.autoWaves.checked=false;state.autoWaves=false;state.autoCountdown=null;updateUI();return}state.autoWaves=ui.autoWaves.checked;if(state.autoWaves&&canStartWave())state.autoCountdown=CONFIG.AUTO_WAVE_COUNTDOWN;else state.autoCountdown=null;updateUI()});
function cycleGameSpeed(){if(state.tutorialActive&&tutorialData.step<18)return;const index=CONFIG.GAME_SPEEDS.indexOf(state.gameSpeed);state.gameSpeed=CONFIG.GAME_SPEEDS[(index+1)%CONFIG.GAME_SPEEDS.length];ui.gameSpeed.textContent=`${state.gameSpeed}×`}
