const targetDescriptions={first:'Attacks the ball closest to the endpoint.',last:'Attacks the ball furthest from the endpoint.',strong:'Attacks the ball with the most current health.',weak:'Attacks the ball with the least current health.'};
function switchTab(tab){const showStats=tab==='stats'&&state.selectedTower;ui.shopPanel.classList.toggle('hidden',showStats);ui.stats.classList.toggle('hidden',!showStats);ui.shopTab.classList.toggle('active',!showStats);ui.statsTab.classList.toggle('active',!!showStats);resizeGameViewport()}
function maxLevel(t){return t.kind==='goldenPapaya'?1:t.kind==='papaya'?CONFIG.PAPAYA_MAX_LEVEL:CONFIG.ELEPHANT_MAX_LEVEL}
function upgradeCost(t){if(t.kind==='goldenPapaya')return 0;const type=t.towerType,water=t.kind==='elephant'&&type==='base',base=t.kind==='papaya'?CONFIG.PAPAYA_BASE_UPGRADE_COST:type==='eyewear'?CONFIG.EYEWEAR_BASE_UPGRADE_COST:type==='foodie'?CONFIG.FOODIE_BASE_UPGRADE_COST:type==='gas'?CONFIG.GAS_MASK_BASE_UPGRADE_COST:type==='splash'?CONFIG.SPLASH_BASE_UPGRADE_COST:CONFIG.ELEPHANT_BASE_UPGRADE_COST,multiplier=t.kind==='papaya'?CONFIG.PAPAYA_UPGRADE_COST_MULTIPLIER:type==='eyewear'?CONFIG.EYEWEAR_UPGRADE_COST_MULTIPLIER:type==='foodie'?CONFIG.FOODIE_UPGRADE_COST_MULTIPLIER:type==='gas'?CONFIG.GAS_MASK_UPGRADE_COST_MULTIPLIER:type==='splash'?CONFIG.SPLASH_UPGRADE_COST_MULTIPLIER:CONFIG.ELEPHANT_UPGRADE_COST_MULTIPLIER,raw=base*Math.pow(multiplier,t.level-1);return water?roundHalfUp(raw):Math.ceil(raw)}
function applyLevelStats(t){const steps=t.level-1,type=t.towerType,baseDamage=type==='eyewear'?CONFIG.EYEWEAR_ELEPHANT_DAMAGE:type==='foodie'?CONFIG.FOODIE_ELEPHANT_DAMAGE:type==='splash'?CONFIG.ELEPHANT_DAMAGE*CONFIG.SPLASH_ELEPHANT_BASE_DAMAGE_MULTIPLIER:CONFIG.ELEPHANT_DAMAGE,baseAttackSpeed=type==='eyewear'?CONFIG.EYEWEAR_ELEPHANT_ATTACK_SPEED:type==='foodie'?CONFIG.ELEPHANT_ATTACK_SPEED/CONFIG.FOODIE_ATTACK_RATE_MULTIPLIER:CONFIG.ELEPHANT_ATTACK_SPEED,baseRadius=type==='eyewear'?CONFIG.EYEWEAR_ELEPHANT_RADIUS:type==='foodie'?CONFIG.FOODIE_ELEPHANT_RADIUS:type==='splash'?CONFIG.ELEPHANT_RADIUS*CONFIG.SPLASH_ELEPHANT_RANGE_MULTIPLIER:CONFIG.ELEPHANT_RADIUS,damageGrowth=type==='splash'?CONFIG.SPLASH_DAMAGE_PER_LEVEL:CONFIG.DAMAGE_PER_LEVEL,rangeGrowth=type==='splash'?CONFIG.SPLASH_RANGE_PER_LEVEL:CONFIG.RANGE_PER_LEVEL;t.damage=baseDamage*Math.pow(1+damageGrowth,steps);t.attackSpeed=baseAttackSpeed/Math.pow(1+CONFIG.ATTACK_SPEED_PER_LEVEL,steps);t.radius=baseRadius*Math.pow(1+rangeGrowth,steps)}
