function sellRefundFor(tower){const originalPurchasePrice=Number(tower?.purchasePrice);return Number.isFinite(originalPurchasePrice)&&originalPurchasePrice>=0?roundHalfUp(originalPurchasePrice*CONFIG.towerSellRate):0}
