function detectNewGhostTiers(){const ghosts=state.balls.filter(orb=>orb.ghost&&orb.targetable&&orb.state==='active'&&!noticedGhostTiers.has(orb.tier)),tiers=[...new Set(ghosts.map(orb=>orb.tier))].sort((a,b)=>a-b);for(const tier of tiers){const candidates=[];for(const tower of state.towers){if(tower.towerType!=='eyewear'||tower.sold)continue;for(const orb of ghosts)if(orb.tier===tier&&canTowerTarget(tower,orb)&&dist(tower,orb)<=tower.radius)candidates.push({tower,orb,distance:dist(tower,orb)})}if(!candidates.length)continue;candidates.sort((a,b)=>a.distance-b.distance||(a.tower.towerId??0)-(b.tower.towerId??0));const detected=candidates[0];noticedGhostTiers.add(tier);recordOrbEncounter(detected.orb,true);saveEncyclopediaData();triggerGhostAlert(detected.tower,tier);showEncyclopediaNotice(`New ghost detected: Tier ${tier} Ghost`);showContextTutorial('ghost','Water Elephants and Foodie Elephants cannot see ghosts. Ghost Scout Elephants can attack them.','#buyEyewear')}}
function damageAgainst(t,target){let typeModifier=1;if(t.towerType==='eyewear'&&!target.ghost)typeModifier=CONFIG.EYEWEAR_NORMAL_ORB_DAMAGE_MULTIPLIER;if(t.towerType==='foodie')typeModifier=target.special&&target.specialType!=='fume'?CONFIG.FOODIE_FOOD_ORB_DAMAGE_MULTIPLIER:CONFIG.FOODIE_NORMAL_ORB_DAMAGE_MULTIPLIER;const tier0Bonus=t.towerType==='base'&&!target.special&&!target.ghost&&target.tier===0?CONFIG.waterElephantTier0DamageMultiplier:1;return t.damage*groupPenaltyMultiplier(t)*typeModifier*tier0Bonus}
