function discoveryColorForOrb(orb){if(orb.special)return'#55e8ff';const entry=encyclopediaEntries().find(item=>item.id===encyclopediaIdForOrb(orb)),visual=entry?.visual||OrbProgression.TIERS[orb.tier||0]?.visual;return visual?.accent||visual?.glow||visual?.mid||'#9b78ff'}
function beginDestructionCollection(orb,earned,unlockIds=[],eaten=false){const discovery=unlockIds.length>0,reduced=discovery&&prefersReducedMotion(),duration=discovery?(reduced?CONFIG.REDUCED_MOTION_DISCOVERY_DURATION:CONFIG.DISCOVERY_SHAKE_DURATION+CONFIG.DISCOVERY_CRACK_DURATION+CONFIG.DISCOVERY_GLOW_DURATION+CONFIG.DISCOVERY_EXPLOSION_DURATION):(eaten?.12:CONFIG.DESTRUCTION_CRACK_DURATION);destructionEffects.push({x:orb.x,y:orb.y,tier:orb.tier||0,ghost:!!orb.ghost,special:!!orb.special,isBoss:!!orb.isBoss,eaten,discovery,reduced,color:discoveryColorForOrb(orb),life:duration,max:duration,earned,unlockIds:[...unlockIds],launched:false})}
function launchCollectionLights(effect){if(effect.launched)return;effect.launched=true;const startScreenX=effect.x,startScreenY=effect.y-state.cameraY;currencyLights.push({startX:effect.x,startY:effect.y,startScreenX,startScreenY,life:CONFIG.CURRENCY_COLLECTION_DURATION,max:CONFIG.CURRENCY_COLLECTION_DURATION,earned:effect.earned,awarded:false});if(effect.unlockIds.length)knowledgeLights.push({startX:effect.x,startY:effect.y,startScreenX,startScreenY,life:CONFIG.KNOWLEDGE_COLLECTION_DURATION,max:CONFIG.KNOWLEDGE_COLLECTION_DURATION,entryIds:[...effect.unlockIds],color:effect.color,completed:false})}
