function splashPulse(t){const targets=state.balls.filter(target=>canTowerTarget(t,target)&&!target.ghost&&dist(t,target)<=t.radius);if(!targets.length)return 0;t.attack=.5;t.recoil=1;splashPulses.push({x:t.x,y:t.y,radius:t.radius,life:.85,max:.85});burst(t.x,t.y,'#75eaff',22,145);for(const target of targets){target.hit=.18;burst(target.x,target.y,'#5edfff',12,95);hitOrb(t,target)}return targets.length}
