function chooseTarget(t,targets){if(t.towerType==='foodie'){const foodTarget=foodTargetForFoodie(t,targets);if(foodTarget)return foodTarget;return normalTargetForTower(t,targets.filter(target=>!target.special&&!target.ghost))}return normalTargetForTower(t,targets)}
