function clearDefeatState(){settlePendingCollections();settlePendingWaveRewards();for(const tower of state.towers){tower.lureOrb=null;tower.behavior='home';if(Number.isFinite(tower.homeX)){tower.x=tower.homeX;tower.y=tower.homeY}}state.balls=[];sprays=[];particles=[]}
function finish(kind){if(state.status!=='playing')return;if(kind==='won')settlePendingWaveRewards();state.status=kind;state.placement=null;if(kind==='lost')clearDefeatState();const h=ui.banner.querySelector('h2'),p=ui.banner.querySelector('p');h.textContent=kind==='won'?'SECTOR SECURED':'PLAYER DEFEATED';p.textContent=`${kind==='won'?`Wave ${CONFIG.TOTAL_WAVES} completed.`:'Your Health reached zero.'} Destroyed: ${state.stats.destroyed} • Escaped: ${state.stats.escaped} • Health lost: ${state.stats.healthLost} • Orb income: ${formatCurrency(state.stats.orbIncome)} • Wave income: ${formatCurrency(state.stats.waveIncome||0)}`;ui.banner.classList.remove('hidden');updateUI()}
function applyEndpointDamage(ball){if(state.status!=='playing'||ball.endpointResolved)return 0;ball.endpointResolved=true;const damage=healthDamageForOrb(ball);state.currentHealth=Math.max(0,state.currentHealth-damage);state.stats.healthLost+=damage;showHealthDamage(damage);updateUI();if(state.currentHealth===0)finish('lost');return damage}
function moveUnit(t,x,y,dt){const dx=x-t.x,dy=y-t.y,d=Math.hypot(dx,dy),step=CONFIG.ELEPHANT_WALK_SPEED*dt;if(d<=step){t.x=x;t.y=y;return true}t.x+=dx/d*step;t.y+=dy/d*step;t.facing=dx>=0?1:-1;t.angle=Math.atan2(dy,Math.abs(dx));return false}
