function update(dt){if(state.paused)return;if(state.status!=='playing'){updateCollectionEffects(dt);return}
  state.gameTime+=dt;
  for(const orb of state.balls)if(orb.specialType==='fume'&&orb.state==='active')orb.fumeScanElapsed=(orb.fumeScanElapsed||0)+dt;
  scanActiveFumeOrbs();
  const cameraDirection=(pressedKeys.has('s')||pressedKeys.has('arrowdown')?1:0)-(pressedKeys.has('w')||pressedKeys.has('arrowup')?1:0);if(cameraDirection)setCameraY(state.cameraY+cameraDirection*CONFIG.CAMERA_SCROLL_SPEED*dt);
  for(const job of state.waveJobs){if(job.spawned<job.total){job.spawnTimer-=dt;if(job.spawnTimer<=0){spawnBall(job);job.spawned++;job.spawnTimer=job.spawnInterval||spawnIntervalForWave(job.wave)}}}
  for(const b of [...state.balls]){if(b.special&&b.state==='active'&&!b.timerExpired){b.lureElapsed+=dt;if(b.lureElapsed>=b.lureDuration){b.timerExpired=true;if(b.specialType==='fume')defeatSpecial(b);else if(b.attracted.length)beginEating(b);else defeatSpecial(b,true)}}let remain=b.state==='active'?orbMovementSpeed(b)*dt:0;b.roll+=remain/BALL_R;while(remain>0&&b.seg<path.length-1){const to=path[b.seg+1],d=Math.hypot(to.x-b.x,to.y-b.y);if(remain>=d){b.x=to.x;b.y=to.y;b.seg++;remain-=d}else{b.x+=(to.x-b.x)/d*remain;b.y+=(to.y-b.y)/d*remain;remain=0}}b.hit=Math.max(0,b.hit-dt);if(b.seg>=path.length-1&&state.balls.includes(b)){b.targetable=false;b.state='escaped';state.balls=state.balls.filter(x=>x!==b);if(b.special)releaseElephants(b);recordOrbEscape(b);state.stats.escaped++;state.shake=Math.min(10,2+healthDamageForOrb(b)*.2);applyEndpointDamage(b);resolveBall(b)}}
  if(state.status!=='playing')return;
  detectNewGhostTiers();
  for(const t of state.towers){t.cooldown-=dt;t.attack=Math.max(0,t.attack-dt);t.recoil=Math.max(0,t.recoil-dt*6);t.fumeFearLife=Math.max(0,(t.fumeFearLife||0)-dt);updateGhostAlert(t,dt);t.walking=false;t.visualTarget=null;t.foodFocus=false;if(t.behavior==='following'){const orb=t.lureOrb;if(!orb||!state.balls.includes(orb)){t.behavior='returning';t.lureOrb=null}else{t.walking=true;moveUnit(t,orb.x-28,orb.y+(t.followIndex?27:-27),dt);continue}}if(t.behavior==='fleeingFumeOrb'){const orb=t.lureOrb;if(!orb||!state.balls.includes(orb)){t.behavior='returning';t.lureOrb=null}else{t.attack=0;t.recoil=0;t.walking=true;const waypoint=t.fleeRoute?.[0]||t.fleeTo;if(moveUnit(t,waypoint.x,waypoint.y,dt)&&t.fleeRoute?.length)t.fleeRoute.shift();continue}}if(t.behavior==='eating'){const orb=t.lureOrb;if(!orb||!state.balls.includes(orb)){t.behavior='returning';t.lureOrb=null}else{t.walking=true;moveUnit(t,orb.x+(t.followIndex?14:-14),orb.y+18,dt);continue}}if(t.behavior==='returning'){t.walking=true;if(moveUnit(t,t.homeX,t.homeY,dt)){t.x=t.homeX;t.y=t.homeY;t.behavior='home';t.angle=-.4}continue}if(t.towerType==='splash'){t.splashPulseCooldown=(Number.isFinite(t.splashPulseCooldown)?t.splashPulseCooldown:CONFIG.SPLASH_PULSE_COOLDOWN)-dt;if(t.splashPulseCooldown<=0&&splashPulse(t)>0)t.splashPulseCooldown=CONFIG.SPLASH_PULSE_COOLDOWN;continue}const targets=state.balls.filter(b=>canTowerTarget(t,b)&&dist(t,b)<=t.radius),target=chooseTarget(t,targets);t.visualTarget=target||null;t.foodFocus=t.towerType==='foodie'&&!!target?.special&&target.specialType!=='fume';if(t.cooldown<=0&&target){fire(t,target);t.cooldown=attackCooldownFor(t,target)}}
  for(const b of [...state.balls])if(b.special&&b.state==='eating'&&b.attracted.length&&b.attracted.every(t=>t.sold||dist(t,b)<38)){b.eatElapsed+=dt;if(b.eatElapsed>=CONFIG.SPECIAL_ORB_EATING_DURATION)defeatSpecial(b,true)}
  for(const p of particles){p.x+=p.vx*dt;p.y+=p.vy*dt;p.vx*=.94;p.vy*=.94;p.life-=dt}particles=particles.filter(p=>p.life>0);for(const s of sprays)s.life-=dt;sprays=sprays.filter(s=>s.life>0);for(const pulse of splashPulses)pulse.life-=dt;splashPulses=splashPulses.filter(pulse=>pulse.life>0);for(const plant of state.goldenPapayas)plant.rewardGlow=Math.max(0,(plant.rewardGlow||0)-dt);updateCollectionEffects(dt);updateWaveRewards(dt);state.shake=Math.max(0,state.shake-dt*18);
  if(state.autoWaves&&canStartWave()){if(state.autoCountdown===null)state.autoCountdown=CONFIG.AUTO_WAVE_COUNTDOWN;state.autoCountdown-=dt;if(state.autoCountdown<=0)launchWave();else updateWaveDisplay()}else if(state.autoCountdown!==null){state.autoCountdown=null;updateWaveDisplay()}
  if(state.wave===CONFIG.TOTAL_WAVES&&state.waveJobs.every(j=>j.resolved===j.total)&&!state.balls.length)finish('won');
}

function drawGround(){const groundHeight=Math.max(CONFIG.WORLD_HEIGHT,state.cameraY+viewportWorldHeight()),ground=ctx.createLinearGradient(0,0,0,groundHeight);ground.addColorStop(0,'#13231f');ground.addColorStop(.48,'#10231f');ground.addColorStop(1,'#16231e');ctx.fillStyle=ground;ctx.fillRect(0,0,CONFIG.WORLD_WIDTH,groundHeight);ctx.strokeStyle='#1b3029';ctx.lineWidth=1;for(let x=-groundHeight;x<CONFIG.WORLD_WIDTH+groundHeight;x+=40){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x-groundHeight,groundHeight);ctx.stroke()}for(let y=0;y<groundHeight;y+=40){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(CONFIG.WORLD_WIDTH,y);ctx.stroke()}for(let i=0;i<Math.ceil(168*groundHeight/CONFIG.WORLD_HEIGHT);i++){const x=(i*173)%CONFIG.WORLD_WIDTH,y=(i*97)%groundHeight;ctx.fillStyle=i%3?'#263b31':'#33493c';ctx.fillRect(x,y,3,3)}}
function drawTrack(){ctx.save();ctx.lineCap='round';ctx.lineJoin='round';ctx.beginPath();ctx.moveTo(path[0].x,path[0].y);path.slice(1).forEach(p=>ctx.lineTo(p.x,p.y));ctx.strokeStyle='#070c0e';ctx.lineWidth=TRACK_WIDTH+14;ctx.stroke();ctx.strokeStyle='#47535a';ctx.lineWidth=TRACK_WIDTH;ctx.stroke();ctx.setLineDash([6,11]);ctx.strokeStyle='#738087';ctx.lineWidth=2;ctx.stroke();ctx.setLineDash([]);ctx.strokeStyle='#232d31';ctx.lineWidth=TRACK_WIDTH-18;ctx.stroke();ctx.restore();const end=path[path.length-1];ctx.fillStyle='#c44b36';ctx.fillRect(end.x-74,end.y-34,15,68);ctx.fillStyle='#ffb12e';for(let y=end.y-31;y<end.y+32;y+=16)ctx.fillRect(end.x-73,y,13,7);ctx.fillStyle='#90a2a7';ctx.font='700 11px Inter';ctx.fillText('EXIT',end.x-92,end.y+55)}
function drawSpecialBall(b){const fume=b.specialType==='fume';ctx.save();ctx.translate(b.x,b.y);ctx.shadowColor=fume?'#aaff45':'#55e8ff';ctx.shadowBlur=14;ctx.rotate(b.roll);const g=ctx.createRadialGradient(-6,-7,2,0,0,BALL_R+2);g.addColorStop(0,b.hit?'#fffbd0':fume?'#d9ff7a':'#f5ffff');g.addColorStop(.27,fume?'#76a932':'#55dff4');g.addColorStop(.7,fume?'#263b1b':'#157caa');g.addColorStop(1,fume?'#07100b':'#082b4e');ctx.fillStyle=g;ctx.beginPath();ctx.arc(0,0,BALL_R+2,0,Math.PI*2);ctx.fill();ctx.strokeStyle=fume?'#c3dc58':'#a9f7ff';ctx.lineWidth=2;ctx.stroke();ctx.rotate(-b.roll);ctx.fillStyle=fume?'#5a3c21':'#85501e';ctx.fillRect(-12,-4,24,13);ctx.fillStyle=fume?'#6d9c25':'#ffad32';for(const x of [-7,0,7]){ctx.beginPath();ctx.ellipse(x,-4,4,6,0,0,Math.PI*2);ctx.fill()}ctx.restore();ctx.save();ctx.translate(b.x,b.y);ctx.globalAlpha=.55+.3*Math.sin(state.gameTime*7);ctx.fillStyle=fume?'#c7ff46':'#ffe76a';ctx.font='15px Inter';ctx.textAlign='center';ctx.fillText(fume?'☣':'✦',0,-32);if(fume){ctx.fillStyle='#39291d';ctx.font='10px Inter';ctx.fillText('⌁',-13,-22);ctx.fillText('⌁',13,-18);for(let i=1;i<4;i++){ctx.globalAlpha=.18/i;ctx.fillStyle='#94e93e';ctx.beginPath();ctx.arc(-i*13,-i*2,7-i,0,Math.PI*2);ctx.fill()}}ctx.restore();ctx.fillStyle='#071012';ctx.fillRect(b.x-22,b.y-27,44,7);ctx.fillStyle=fume?'#a4e63e':'#55e5f2';ctx.fillRect(b.x-21,b.y-26,42*(b.durability/b.maxDurability),5);ctx.fillStyle='#e9ffff';ctx.font='700 8px Inter';ctx.textAlign='center';ctx.fillText(`${b.durability}/${b.maxDurability}`,b.x,b.y-31);ctx.textAlign='left'}
