function drawGhostGlassesLocal(glassesAnchor,ghost,valid){const frame=ghost?(valid?'#72f3e5':'#ff8b83'):'#71efff',left={x:glassesAnchor.x-5,y:glassesAnchor.y-.5},right={x:glassesAnchor.x+5,y:glassesAnchor.y+.5};ctx.save();ctx.shadowColor=frame;ctx.shadowBlur=ghost?3:7;ctx.strokeStyle='#294b55';ctx.lineWidth=2.5;ctx.beginPath();ctx.moveTo(left.x-9,left.y-1);ctx.lineTo(left.x-4,left.y);ctx.moveTo(right.x+4,right.y);ctx.lineTo(right.x+9,right.y+2);ctx.stroke();ctx.strokeStyle=frame;ctx.fillStyle=ghost?(valid?'#72f3e533':'#ff8b8333'):'#a9f9ff44';ctx.lineWidth=2.3;for(const lens of [left,right]){ctx.beginPath();ctx.ellipse(lens.x,lens.y,5.2,4.8,0,0,Math.PI*2);ctx.fill();ctx.stroke()}ctx.beginPath();ctx.moveTo(left.x+5,left.y);ctx.quadraticCurveTo(glassesAnchor.x,glassesAnchor.y+1,right.x-5,right.y);ctx.stroke();ctx.restore()}
function drawFoodiePapayaLocal(t,anchors,ghost,valid){const pose=anchors.foodPose;if(!pose||pose.hidden)return;ctx.save();ctx.translate(anchors.foodAnchor.x,anchors.foodAnchor.y);ctx.rotate(pose.rotation);ctx.fillStyle=ghost?(valid?'#5fd887':'#ff7b71'):'#4f9b4b';ctx.beginPath();ctx.ellipse(0,0,10,7,0,0,Math.PI*2);ctx.fill();ctx.fillStyle=ghost?'#ffc35b99':'#f39a36';ctx.beginPath();ctx.ellipse(1,0,7,4.5,0,0,Math.PI*2);ctx.fill();ctx.fillStyle='#35251d';for(const seed of [{x:-2,y:-1},{x:1,y:1},{x:4,y:-1}]){ctx.beginPath();ctx.ellipse(seed.x,seed.y,1.1,.7,.4,0,Math.PI*2);ctx.fill()}ctx.strokeStyle='#2e7136';ctx.lineWidth=1.5;ctx.stroke();ctx.restore();ctx.strokeStyle=ghost?(valid?'#d9fff0':'#ffd8d4'):'#65777b';ctx.lineWidth=3.5;ctx.beginPath();ctx.arc(anchors.foodAnchor.x-4,anchors.foodAnchor.y+1,5,-1.25,.7);ctx.stroke();ctx.strokeStyle=ghost?(valid?'#d9fff0':'#ffd8d4'):'#273b3c';ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(29,-1+pose.chew);ctx.quadraticCurveTo(32,1+pose.chew,35,-1+pose.chew);ctx.stroke()}
function drawElephant(t,ghost=false,valid=true,selected=false){ctx.save();ctx.translate(t.x,t.y);ctx.globalAlpha=ghost?.7:1;if(t.fumeAffected&&!ghost&&(t.fumeFearLife||0)>0){ctx.save();ctx.globalAlpha=.22+.12*Math.sin(state.gameTime*12);ctx.fillStyle='#9dff44';ctx.beginPath();ctx.arc(0,-2,39,0,Math.PI*2);ctx.fill();ctx.fillStyle='#d8ff76';ctx.font='700 19px Inter';ctx.textAlign='center';ctx.fillText('!',0,-39);ctx.restore()}if(selected){ctx.shadowColor='#ffd43b';ctx.shadowBlur=16;ctx.strokeStyle='#ffd43b';ctx.lineWidth=3;ctx.beginPath();ctx.ellipse(0,4,36,34,0,0,Math.PI*2);ctx.stroke()}ctx.fillStyle=ghost?(valid?'#4cf0d044':'#ff514744'):'#091315';ctx.beginPath();ctx.ellipse(0,19,34,13,0,0,Math.PI*2);ctx.fill();ctx.scale(t.facing||1,1);ctx.rotate(t.angle||0);const bob=ghost?0:Math.sin(state.gameTime*(t.walking?8:3.6)+t.x)*(t.walking?4:2);ctx.translate(-(t.recoil||0)*5,bob);const anchors=elephantAttachmentAnchors(t),skin=ghost?(valid?'#62e5d5':'#ff6b62'):'#84979b';ctx.strokeStyle='#506267';ctx.lineWidth=7;[-14,12].forEach(x=>{ctx.beginPath();ctx.moveTo(x,12);ctx.lineTo(x,27+(t.walking?Math.sin(state.gameTime*10+x)*4:0));ctx.stroke()});ctx.fillStyle=skin;ctx.beginPath();ctx.ellipse(0,0,25,20,0,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(anchors.headPosition.x,anchors.headPosition.y,16,0,Math.PI*2);ctx.fill();ctx.fillStyle='#65777b';ctx.beginPath();ctx.ellipse(11,-8,10,16,-.5,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#e2e9e8';ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(28,3);ctx.lineTo(38,8);ctx.stroke();ctx.fillStyle='#162126';for(const eye of [{x:18.5,y:-10.2,r:1.8},{x:27.5,y:-8.5,r:2.2}]){ctx.beginPath();ctx.arc(eye.x,eye.y,eye.r,0,Math.PI*2);ctx.fill()}if(t.towerType==='eyewear')drawGhostGlassesLocal(anchors.glassesAnchor,ghost,valid);if(t.towerType==='gas'){ctx.fillStyle='#263539';ctx.strokeStyle='#9cefc3';ctx.lineWidth=2;ctx.beginPath();ctx.roundRect(12,-16,24,18,6);ctx.fill();ctx.stroke();ctx.fillStyle='#a8f4d2';for(const x of [18,30]){ctx.beginPath();ctx.arc(x,-7,4,0,Math.PI*2);ctx.fill()}ctx.strokeStyle='#44585d';ctx.beginPath();ctx.moveTo(12,-12);ctx.lineTo(4,-16);ctx.moveTo(36,-12);ctx.lineTo(41,-16);ctx.stroke()}ctx.strokeStyle=skin;ctx.lineWidth=9;ctx.lineCap='round';ctx.beginPath();ctx.moveTo(27,2);ctx.quadraticCurveTo(37,8,anchors.foodAnchor.x,anchors.foodAnchor.y);ctx.stroke();if(t.towerType==='foodie')drawFoodiePapayaLocal(t,anchors,ghost,valid);ctx.restore()}
function drawGhostAlert(t){const alert=t.ghostAlert;if(!alert)return;const progress=1-alert.life/alert.max,reduced=prefersReducedMotion(),rise=reduced?0:Math.sin(Math.min(1,progress/.45)*Math.PI)*12,scale=reduced?1:1+Math.sin(Math.min(1,progress/.35)*Math.PI)*.45;ctx.save();ctx.translate(t.x,t.y-48-rise);ctx.scale(scale,scale);ctx.globalAlpha=Math.min(1,alert.life/.22);ctx.fillStyle='#bdfbff';ctx.shadowColor='#55e8ff';ctx.shadowBlur=12;ctx.font='900 25px Inter';ctx.textAlign='center';ctx.fillText('!',0,0);ctx.textAlign='left';ctx.restore()}
