function drawSpray(s){const alpha=s.life/s.max,dx=s.x2-s.x1,dy=s.y2-s.y1,len=Math.hypot(dx,dy),nx=-dy/len,ny=dx/len;ctx.save();ctx.globalAlpha=alpha;ctx.lineCap='round';const g=ctx.createLinearGradient(s.x1,s.y1,s.x2,s.y2);g.addColorStop(0,'#e8ffff');g.addColorStop(.3,'#72e8ff');g.addColorStop(1,'#27a9dc22');ctx.strokeStyle=g;ctx.lineWidth=5+alpha*4;ctx.beginPath();ctx.moveTo(s.x1,s.y1);ctx.quadraticCurveTo((s.x1+s.x2)/2+nx*10,(s.y1+s.y2)/2+ny*10,s.x2,s.y2);ctx.stroke();ctx.fillStyle='#bffaff';for(let i=1;i<8;i++){const p=i/8,w=Math.sin(i*4.7+s.seed)*7*(1-p),x=s.x1+dx*p+nx*w,y=s.y1+dy*p+ny*w;ctx.beginPath();ctx.arc(x,y,2+3*(1-p),0,Math.PI*2);ctx.fill()}if(s.splash){ctx.strokeStyle='#9ff5ff';ctx.lineWidth=2;ctx.beginPath();ctx.arc(s.x2,s.y2,CONFIG.SPLASH_RADIUS*(1-alpha*.35),0,Math.PI*2);ctx.stroke()}ctx.restore()}
