function drawGhostBall(b){ctx.save();ctx.globalAlpha=.55;ctx.shadowColor='#d8fbff';ctx.shadowBlur=18;for(let i=0;i<3;i++){ctx.fillStyle=`rgba(205,247,255,${.09-i*.02})`;ctx.beginPath();ctx.arc(b.x-12-i*9,b.y+Math.sin(state.gameTime*4+i)*5,12-i*2,0,Math.PI*2);ctx.fill()}drawBall(b);ctx.restore()}
function drawDestructionEffects(){for(const effect of destructionEffects){const progress=1-effect.life/effect.max,visual=OrbProgression.TIERS[effect.tier]?.visual||{highlight:'#f5ffff',mid:'#64dce8',low:'#157caa',shadow:'#082b4e',accent:'#c9ffff'};if(!effect.discovery){const shake=(1-progress)*Math.sin(state.gameTime*65)*4;ctx.save();ctx.translate(effect.x+shake,effect.y);ctx.globalAlpha=1-progress*.65;ctx.shadowColor=effect.ghost?'#e5ffff':visual.accent;ctx.shadowBlur=8+progress*18;ctx.fillStyle=effect.eaten?'#ffb33b':visual.mid;ctx.beginPath();ctx.arc(0,0,BALL_R*(1-progress*.18),0,Math.PI*2);ctx.fill();ctx.strokeStyle=effect.ghost?'#f0ffff':'#fff4bb';ctx.lineWidth=1+progress*3;for(let i=0;i<5;i++){const a=i*1.27+progress;ctx.beginPath();ctx.moveTo(Math.cos(a)*3,Math.sin(a)*3);ctx.lineTo(Math.cos(a+.25)*BALL_R*(.35+progress*.55),Math.sin(a+.25)*BALL_R*(.35+progress*.55));ctx.stroke()}ctx.restore();continue}const total=effect.max,shakeEnd=effect.reduced?.2:CONFIG.DISCOVERY_SHAKE_DURATION/total,crackEnd=effect.reduced?.58:(CONFIG.DISCOVERY_SHAKE_DURATION+CONFIG.DISCOVERY_CRACK_DURATION)/total,glowEnd=effect.reduced?.78:(CONFIG.DISCOVERY_SHAKE_DURATION+CONFIG.DISCOVERY_CRACK_DURATION+CONFIG.DISCOVERY_GLOW_DURATION)/total,shakeProgress=Math.min(1,progress/Math.max(.01,shakeEnd)),crackProgress=Math.max(0,Math.min(1,(progress-shakeEnd)/Math.max(.01,crackEnd-shakeEnd))),glowProgress=Math.max(0,Math.min(1,(progress-crackEnd)/Math.max(.01,glowEnd-crackEnd))),explosionProgress=Math.max(0,Math.min(1,(progress-glowEnd)/Math.max(.01,1-glowEnd))),shake=effect.reduced?Math.sin(state.gameTime*48)*.8:Math.sin(state.gameTime*(48+shakeProgress*45))*(.4+shakeProgress*4.8);ctx.save();ctx.translate(effect.x+shake,effect.y+Math.cos(state.gameTime*71)*shake*.22);const lightStrength=Math.max(crackProgress*.3,glowProgress,explosionProgress);ctx.shadowColor=effect.color;ctx.shadowBlur=6+lightStrength*28;if(effect.eaten){ctx.globalAlpha=1-explosionProgress;ctx.fillStyle='#ffb33b';ctx.beginPath();ctx.arc(0,0,6+glowProgress*5,0,Math.PI*2);ctx.fill()}else{ctx.globalAlpha=1-explosionProgress*.9;const gradient=ctx.createRadialGradient(-5,-6,1,0,0,BALL_R);gradient.addColorStop(0,visual.highlight||'#fff');gradient.addColorStop(.35,visual.mid||effect.color);gradient.addColorStop(.78,visual.low||'#345');gradient.addColorStop(1,visual.shadow||'#111');ctx.fillStyle=gradient;ctx.beginPath();ctx.arc(0,0,BALL_R*(1-explosionProgress*.12),0,Math.PI*2);ctx.fill();const cracks=Math.ceil(crackProgress*8);ctx.strokeStyle=glowProgress>.05?'#f5ffff':effect.color;ctx.lineWidth=1+glowProgress*2;for(let i=0;i<cracks;i++){const a=i*2.19+.35,length=4+crackProgress*(7+(i%3)*2);ctx.beginPath();ctx.moveTo(Math.cos(a)*2,Math.sin(a)*2);ctx.lineTo(Math.cos(a+.12)*length*.55,Math.sin(a+.12)*length*.55);ctx.lineTo(Math.cos(a-.08)*length,Math.sin(a-.08)*length);ctx.stroke()}}if(explosionProgress>0){ctx.globalAlpha=1-explosionProgress;ctx.fillStyle=effect.color;for(let i=0;i<9;i++){const a=i*.7+.2,distance=4+explosionProgress*24;ctx.save();ctx.translate(Math.cos(a)*distance,Math.sin(a)*distance);ctx.rotate(a+explosionProgress*3);ctx.fillRect(-2,-1,4,3);ctx.restore()}}ctx.globalAlpha=Math.min(1,glowProgress*1.4+explosionProgress);ctx.fillStyle='#f8ffff';ctx.shadowColor=effect.color;ctx.shadowBlur=24;ctx.beginPath();ctx.arc(0,0,3+lightStrength*5,0,Math.PI*2);ctx.fill();ctx.restore()}}
function collectionTarget(element,fallbackX){const canvasRect=canvas.getBoundingClientRect(),rect=element?.getBoundingClientRect?.();return rect?{x:(rect.left+rect.width/2-canvasRect.left)*CONFIG.WORLD_WIDTH/canvasRect.width,y:(rect.top+rect.height/2-canvasRect.top)*viewportWorldHeight()/canvasRect.height}:{x:fallbackX,y:24}}
function drawCollectionLights(){const currencyTarget=collectionTarget(extendedUI.currencyStat,CONFIG.WORLD_WIDTH-65),knowledgeTarget=collectionTarget(ui.openEncyclopedia,95);for(const light of currencyLights){const progress=1-light.life/light.max,startX=light.startScreenX??light.startX,startY=light.startScreenY??light.startY-state.cameraY,eased=1-Math.pow(1-progress,2),x=startX+(currencyTarget.x-startX)*eased,y=startY+(currencyTarget.y-startY)*eased-48*Math.sin(progress*Math.PI);ctx.save();ctx.globalAlpha=Math.min(1,light.life*5);ctx.fillStyle='#ffd34d';ctx.shadowColor='#ffca36';ctx.shadowBlur=14;ctx.beginPath();ctx.arc(x,y,5,0,Math.PI*2);ctx.fill();ctx.restore()}for(const light of knowledgeLights){const progress=1-light.life/light.max,startX=light.startScreenX??light.startX,startY=light.startScreenY??light.startY-state.cameraY,eased=1-Math.pow(1-progress,3),x=startX+(knowledgeTarget.x-startX)*eased,y=startY+(knowledgeTarget.y-startY)*eased-82*Math.sin(progress*Math.PI),radius=7-progress*2.5,color=light.color||'#9b78ff';ctx.save();for(let i=4;i>=1;i--){const trailProgress=Math.max(0,progress-i*.035),trailEase=1-Math.pow(1-trailProgress,3),trailX=startX+(knowledgeTarget.x-startX)*trailEase,trailY=startY+(knowledgeTarget.y-startY)*trailEase-82*Math.sin(trailProgress*Math.PI);ctx.globalAlpha=(5-i)*.08*Math.min(1,light.life*6);ctx.fillStyle=color;ctx.beginPath();ctx.arc(trailX,trailY,Math.max(1,radius-i*.8),0,Math.PI*2);ctx.fill()}ctx.globalAlpha=Math.min(1,light.life*6);ctx.fillStyle='#f7ffff';ctx.shadowColor=color;ctx.shadowBlur=22;ctx.beginPath();ctx.arc(x,y,radius,0,Math.PI*2);ctx.fill();ctx.strokeStyle=color;ctx.lineWidth=2;ctx.stroke();ctx.restore()}}
function drawWaveRewardLights(){const target={x:CONFIG.WORLD_WIDTH-65,y:24};for(const reward of state.pendingWaveRewards){const progress=1-reward.life/reward.max,startY=reward.startY-state.cameraY,x=reward.startX+(target.x-reward.startX)*progress,y=startY+(target.y-startY)*progress-70*Math.sin(progress*Math.PI);ctx.save();ctx.globalAlpha=Math.min(1,reward.life*6);ctx.fillStyle='#ffd34d';ctx.shadowColor='#ffb51f';ctx.shadowBlur=18;ctx.beginPath();ctx.arc(x,y,7-progress*2,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#fff0a2';ctx.lineWidth=2;ctx.stroke();ctx.restore()}}
