function normalizeTutorialData(value){let source=value;try{if(typeof source==='string')source=JSON.parse(source)}catch{source=null}source=source&&typeof source==='object'?source:{};return{started:!!source.started,step:Math.max(0,Math.min(CONFIG.TUTORIAL_STEP_COUNT-1,Number.isFinite(source.step)?Math.floor(source.step):0)),completed:!!source.completed,skipped:!!source.skipped,doNotShow:!!source.doNotShow,contexts:source.contexts&&typeof source.contexts==='object'?{...source.contexts}:{}}}
function loadTutorialData(){try{return normalizeTutorialData(typeof localStorage!=='undefined'?localStorage.getItem(CONFIG.TUTORIAL_STORAGE_KEY):null)}catch{return normalizeTutorialData(null)}}
function saveTutorialData(){try{if(typeof localStorage!=='undefined')localStorage.setItem(CONFIG.TUTORIAL_STORAGE_KEY,JSON.stringify(tutorialData))}catch{}}
let tutorialData=loadTutorialData();
function startTutorialIfNeeded(){if(tutorialData.completed||tutorialData.skipped||tutorialData.doNotShow)return;state.gameSpeed=1;state.autoWaves=false;state.autoCountdown=null;ui.autoWaves.checked=false;ui.gameSpeed.textContent='1×';state.tutorialActive=true;tutorialData.started=true;saveTutorialData();renderTutorial()}
function replayTutorial(){state.contextTutorial=null;state.tutorialActive=true;tutorialData.step=0;tutorialData.completed=false;tutorialData.skipped=false;state.gameSpeed=1;state.autoWaves=false;state.cameraY=0;lowerMapDiscovered=false;saveLowerMapDiscovery();tutorialPlacementGuide={signature:'',recommended:null,fallback:[]};saveTutorialData();updateScrollDiscoveryHint();renderTutorial()}
function renderTutorial(){const step=TUTORIAL_STEPS[tutorialData.step];if(!state.tutorialActive||!step)return;if(step.require==='scroll'&&lowerMapDiscovered){advanceTutorial();return}if(step.require==='scroll')tutorialScrollStartY=state.cameraY;tutorialPlacementGuide.signature='';extendedUI.tutorialOverlay.classList.remove('hidden');extendedUI.tutorialProgress.textContent=`TUTORIAL ${tutorialData.step+1} / ${CONFIG.TUTORIAL_STEP_COUNT}`;extendedUI.tutorialTitle.textContent=step.title;extendedUI.tutorialText.textContent=step.text;extendedUI.tutorialDoNotShow.checked=tutorialData.doNotShow;extendedUI.tutorialContinue.disabled=!!step.require;extendedUI.tutorialContinue.textContent=step.require?'COMPLETE HIGHLIGHTED ACTION':tutorialData.step===CONFIG.TUTORIAL_STEP_COUNT-1?'FINISH':'CONTINUE';updateScrollDiscoveryHint();positionTutorialSpotlight()}
