function positionTutorialSpotlight(){if(!state?.tutorialActive||extendedUI.tutorialOverlay.classList.contains?.('hidden'))return;const step=TUTORIAL_STEPS[tutorialData.step],placementGuide=tutorialPlacementGuidanceActive(),rect=tutorialTargetRect(step?.target||'#game'),padding=placementGuide?0:8;extendedUI.tutorialSpotlight.classList.toggle('placement-range',placementGuide);if(!rect){extendedUI.tutorialSpotlight.style.display='none';extendedUI.tutorialPlacementMarker.style.display='none';extendedUI.tutorialPointer.style.display='none';return}extendedUI.tutorialSpotlight.style.display='block';extendedUI.tutorialPointer.style.display='block';extendedUI.tutorialSpotlight.style.left=`${rect.left-padding}px`;extendedUI.tutorialSpotlight.style.top=`${rect.top-padding}px`;extendedUI.tutorialSpotlight.style.width=`${rect.width+padding*2}px`;extendedUI.tutorialSpotlight.style.height=`${rect.height+padding*2}px`;extendedUI.tutorialPointer.style.left=`${Math.max(8,rect.left-38)}px`;extendedUI.tutorialPointer.style.top=`${rect.top+rect.height/2-15}px`;const recommended=placementGuide?updateTutorialPlacementGuide().recommended:null;if(recommended){const footprint=tutorialWorldCircleRect(recommended,TOWER_R);extendedUI.tutorialPlacementMarker.style.display='block';extendedUI.tutorialPlacementMarker.style.left=`${footprint.left}px`;extendedUI.tutorialPlacementMarker.style.top=`${footprint.top}px`;extendedUI.tutorialPlacementMarker.style.width=`${footprint.width}px`;extendedUI.tutorialPlacementMarker.style.height=`${footprint.height}px`}else extendedUI.tutorialPlacementMarker.style.display='none'}
